Actionscript.script:
stop();

import flash.events.MouseEvent;
import flash.display.Shape;
import flash.display.MovieClip;
import flash.utils.Timer;
import flash.events.TimerEvent;

// --- VARIABEL GLOBAL ---
if (Object(this).skorTotalGame == undefined) Object(this).skorTotalGame = 0; 
if (Object(this).waktuTotalGame == undefined) Object(this).waktuTotalGame = 0; 

var levelCTD:int = 1;
var gameSelesai:Boolean = false;
var startX:Number;
var startY:Number;
var activeBlock:MovieClip; // Variabel yang tadi error
var activeIndex:int;
var timerGame:Timer = new Timer(1000); 
var isTimerBerjalan:Boolean = false;
var lines:Array = [];

for (var i:int = 1; i <= 4; i++) {
    lines[i] = new Shape();
    addChild(lines[i]);
}

var semuaKunci:Array = [null, 
    { "btnkiri1":"btnkanan4", "btnkiri2":"btnkanan3", "btnkiri3":"btnkanan1", "btnkiri4":"btnkanan2" },
    { "btnkiri1":"btnkanan4", "btnkiri2":"btnkanan1", "btnkiri3":"btnkanan3", "btnkiri4":"btnkanan2" },
    { "btnkiri1":"btnkanan1", "btnkiri2":"btnkanan2", "btnkiri3":"btnkanan3", "btnkiri4":"btnkanan4" },
    { "btnkiri1":"btnkanan4", "btnkiri2":"btnkanan3", "btnkiri3":"btnkanan2", "btnkiri4":"btnkanan1" },
    { "btnkiri1":"btnkanan2", "btnkiri2":"btnkanan4", "btnkiri3":"btnkanan1", "btnkiri4":"btnkanan3" }
];

function jalankanTimer():void {
    if (!isTimerBerjalan) {
        timerGame.addEventListener(TimerEvent.TIMER, function(e:TimerEvent){
            Object(this).waktuTotalGame++;
            var m:int = Math.floor(Object(this).waktuTotalGame / 60);
            var s:int = Object(this).waktuTotalGame % 60;
            txt_timer.text = (m<10?"0"+m:m) + "." + (s<10?"0"+s:s);
        });
        timerGame.start();
        isTimerBerjalan = true;
    }
}

function setupLevel():void {
    txt_poinangka.text = String(Object(this).skorTotalGame);
    for (var j:int = 1; j <= 4; j++) {
        lines[j].graphics.clear();
        var btn:MovieClip = this["btnkiri" + j];
        btn.index = j; btn.connectedTo = null;
        btn.addEventListener(MouseEvent.MOUSE_DOWN, function(e:MouseEvent){
            activeBlock = e.currentTarget as MovieClip;
            stage.addEventListener(MouseEvent.MOUSE_MOVE, onDragging);
            stage.addEventListener(MouseEvent.MOUSE_UP, onDragDrop);
        });
    }
    btn_lanjutctd.addEventListener(MouseEvent.CLICK, onLanjutClick);
    jalankanTimer();
}

function onDragging(e:MouseEvent):void {
    lines[activeBlock.index].graphics.clear();
    lines[activeBlock.index].graphics.lineStyle(5, 0x3399FF);
    lines[activeBlock.index].graphics.moveTo(activeBlock.x + activeBlock.width, activeBlock.y + activeBlock.height/2);
    lines[activeBlock.index].graphics.lineTo(mouseX, mouseY);
}

function onDragDrop(e:MouseEvent):void {
    stage.removeEventListener(MouseEvent.MOUSE_MOVE, onDragging);
    stage.removeEventListener(MouseEvent.MOUSE_UP, onDragDrop);
    for (var k:int = 1; k <= 4; k++) {
        var target:MovieClip = this["btnkanan" + k];
        if (target.hitTestPoint(mouseX, mouseY, true)) {
            activeBlock.connectedTo = target.name;
            return;
        }
    }
    lines[activeBlock.index].graphics.clear();
}

function onLanjutClick(e:MouseEvent):void {
    var kunci:Object = semuaKunci[levelCTD];
    for (var m:int = 1; m <= 4; m++) {
        if (this["btnkiri"+m].connectedTo == kunci[this["btnkiri"+m].name]) Object(this).skorTotalGame += 25;
    }
    if (levelCTD < 5) { levelCTD++; nextFrame(); } 
    else { timerGame.stop(); gotoAndStop(1, "DTB"); }
}
setupLevel();

setupLevel();

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;

setupLevel();

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;

setupLevel();

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;

setupLevel();

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;

stop();

import flash.events.MouseEvent;
import flash.display.MovieClip;
import flash.utils.Timer;
import flash.events.TimerEvent;

// --- VARIABEL ---
if (Object(this).skorTotalGame == undefined) Object(this).skorTotalGame = 0; 
if (Object(this).waktuTotalGame == undefined) Object(this).waktuTotalGame = 0; 
var levelDTB:int = 1;
var jawabanPemain:MovieClip; // Variabel yang tadi error
var timerGameDTB:Timer = new Timer(1000);

var dataLevelDTB:Array = [null,
    {soal: "int main() { [ Zona 1 ] << \"Halo\"; }", kunci: "btn_jawaban2", nilai: ["cin","cout","get","print"]},
    {soal: "int x = 10; [ Zona 1 ] (x > 5) { }", kunci: "btn_jawaban1", nilai: ["if","else","for","while"]},
    {soal: "switch(x) { case 1: [ Zona 1 ] }", kunci: "btn_jawaban4", nilai: ["stop;","exit;","return;","break;"]},
    {soal: "[ Zona 1 ] (int i=0; i<5; i++) {}", kunci: "btn_jawaban3", nilai: ["while","do","for","loop"]},
    {soal: "do { } [ Zona 1 ] (x < 5);", kunci: "btn_jawaban2", nilai: ["if","while","until","for"]}
];

timerGameDTB.addEventListener(TimerEvent.TIMER, function(e:TimerEvent){
    Object(this).waktuTotalGame++;
    var m:int = Math.floor(Object(this).waktuTotalGame / 60);
    var s:int = Object(this).waktuTotalGame % 60;
    txt_timer.text = (m<10?"0"+m:m) + "." + (s<10?"0"+s:s);
});
timerGameDTB.start();

function setupLevelDTB():void {
    txt_poinangka.text = String(Object(this).skorTotalGame);
    var d:Object = dataLevelDTB[levelDTB];
    txt_soal.htmlText = d.soal;
    for (var j:int = 1; j <= 4; j++) {
        var b:MovieClip = this["btn_jawaban"+j];
        b.nilaiTeks = d.nilai[j-1];
        b.txt_label.text = b.nilaiTeks;
        b.addEventListener(MouseEvent.MOUSE_DOWN, function(e:MouseEvent){ 
            jawabanPemain = e.currentTarget as MovieClip; 
            jawabanPemain.startDrag(); 
        });
        b.addEventListener(MouseEvent.MOUSE_UP, function(e:MouseEvent){
            var b:MovieClip = e.currentTarget as MovieClip;
            b.stopDrag();
            if (b.hitTestObject(dropZone)) {
                txt_soal.htmlText = d.soal.replace("[ Zona 1 ]", "<font color='#FF0000'>"+b.nilaiTeks+"</font>");
            }
        });
    }
    btn_lanjutdtb.addEventListener(MouseEvent.CLICK, function(e:MouseEvent){
        if (jawabanPemain && jawabanPemain.name == d.kunci) Object(this).skorTotalGame += 25;
        if (levelDTB < 5) { levelDTB++; nextFrame(); } 
        else { timerGameDTB.stop(); gotoAndStop(1, "Skor"); }
    });
}
setupLevelDTB();

stop();

// 1. Tampilkan Total Skor dari Ingatan Gaib
if (Object(this).skorTotalGame != undefined) {
    txt_poinAkhir.text = String(Object(this).skorTotalGame);
} else {
    txt_poinAkhir.text = "0"; // Jaga-jaga kalau dites langsung dari scene ini
}

// 2. Format dan Tampilkan Total Waktu Akhir
if (Object(this).waktuTotalGame != undefined) {
    var menitAkhir:int = Math.floor(Object(this).waktuTotalGame / 60);
    var detikAkhir:int = Object(this).waktuTotalGame % 60;

    var teksMenit:String = (menitAkhir < 10) ? "0" + menitAkhir : String(menitAkhir);
    var teksDetik:String = (detikAkhir < 10) ? "0" + detikAkhir : String(detikAkhir);

    // Menggabungkan dengan titik dua seperti desain UI "02:15"
    txt_waktuAkhir.text = teksMenit + ":" + teksDetik;
} else {
    txt_waktuAkhir.text = "00:00";
}
